SELECT SUM(emission_value) AS total_co2_emissions
FROM ghg_emissions
WHERE ghg_type = 'CO2';

SELECT COUNT(compliance_table_id) AS finalized_tables_count
FROM compliance_tables
WHERE compliance_table_status = 'Finalized';

SELECT compliance_table_name
FROM compliance_tables
WHERE compliance_table_status = 'Finalized';

SELECT material_topic_name
FROM material_topics
WHERE material_topic_status = 'active';

SELECT goal_name
FROM sustainable_goals
WHERE goal_status = 'in progress';

SELECT COUNT(*) AS active_material_topics
FROM material_topics
WHERE material_topic_status = 'Active';

SELECT metric_name, metric_value
FROM impact_metrics
WHERE metric_status = 'active' AND metric_value > metric_baseline_value;

SELECT material_topic_name
FROM material_topics
WHERE material_topic_status = 'active';

SELECT COALESCE(material_topic_name, 'Unknown') AS material_topic_name
FROM material_topics
ORDER BY material_topic_name;
